public int[][] rotateGrid(int[][] grid, int k) {
    int m = grid.length, n = grid[0].length;
    int layers = Math.min(m, n) / 2;
    for (int layer = 0; layer < layers; layer++) {
        rotateLayer(grid, layer, k);
    }
    return grid;
}

private void rotateLayer(int[][] matrix, int layer, int k) {
    int m = matrix.length, n = matrix[0].length;
    int top = layer, bottom = m - 1 - layer;
    int left = layer, right = n - 1 - layer;
    int data_in_layer = (right - left + 1) * 2 + (bottom - top - 1) * 2;
    k %= data_in_layer;
    while (k-- > 0) {
        int temp = matrix[top][left];
        for (int j = left; j < right; j++) matrix[top][j] = matrix[top][j + 1];
        for (int i = top; i < bottom; i++) matrix[i][right] = matrix[i + 1][right];
        for (int j = right; j > left; j--) matrix[bottom][j] = matrix[bottom][j - 1];
        for (int i = bottom; i > top; i--) matrix[i][left] = matrix[i - 1][left];
        matrix[top + 1][left] = temp;
    }
}
